handlerUpdate.perform:
const lever = indirect;
const turnstile = object;
const exit = lib.ref('exit:gate:north');

if (!lever.tags.includes('turnstile-fix')) {
  return { output: `The ${lib.ref(lever)} doesn't fit the socket. You need something more substantial.`, events: [] };
}

// Update the turnstile
const turnstileUpdate = {
  type: 'entity-update',
  entityId: turnstile.id,
  name: 'turnstile (fixed)',
  description: 'The brass turnstile now has a rusty lever slotted firmly into its socket. It looks ready to use.',
  properties: { fixed: true }
};

// Unlock the exit
const exitUpdate = {
  type: 'set-property',
  entityId: 'exit:gate:north',
  property: 'locked',
  value: false,
  description: 'The turnstile unlocks.'
};

// Move lever to turnstile (effectively "installing" it)
const leverUpdate = {
  type: 'set-property',
  entityId: lever.id,
  property: 'location',
  value: turnstile.id,
  description: 'Lever installed.'
};

return {
  output: `You slot the ${lib.ref(lever)} into the socket. It fits with a satisfying, metallic clunk. The gears inside the turnstile grind briefly, then settle into a position that suggests the way is now open.`,
  events: [turnstileUpdate, exitUpdate, leverUpdate]
};

